test('electronic submission wording maps to SUBMISSION_METHOD',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Hard copies will not be accepted. Electronic submission required by email.',category:'Other',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'submit'}); assert(out.canonicalRequirements?.some(r=>r.canonicalKey==='SUBMISSION_METHOD'));});
test('FOB destination wording creates clean commercial keys and titles',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Quote net pricing FOB LSU Destination inclusive of shipping.',category:'Commercial',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'fob'}); const req=out.canonicalRequirements?.find(r=>r.canonicalKey==='FOB_DESTINATION_PRICING'); assert.equal(req?.canonicalKey,'FOB_DESTINATION_PRICING'); assert.equal(req?.title,'FOB Destination Pricing'); assert(!/COMMERCIAL_COMMERCIAL|OTHER_OTHER|Commercial Commercial|Other Other/.test(`${req?.canonicalKey} ${req?.title}`));});
test('duplicate commercial wording deduplicates without Other duplicate',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],id:'c1',requirement:'Quote net pricing FOB LSU Destination inclusive of shipping.',category:'Commercial',status:'Unknown'},{...sample.complianceMatrix[0],id:'c2',requirement:'FOB Destination pricing is required.',category:'Other',status:'Needs Clarification'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'fob-dedupe'}); assert.equal(out.canonicalRequirements?.filter(r=>r.canonicalKey==='FOB_DESTINATION_PRICING').length,1); assert(!out.canonicalRequirements?.some(r=>/^OTHER_OTHER|^COMMERCIAL_COMMERCIAL/.test(r.canonicalKey)));});
test('canonical titles never contain repeated category prefixes',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Commercial quote net pricing FOB destination inclusive of shipping and handling.',category:'Commercial',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Other late receipt at lsubids.edu late bids will not be accepted.',category:'Other',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'titles'}); for(const r of out.canonicalRequirements||[]) assert(!/(Commercial Commercial|Other Other|Administrative Administrative|Submission Submission)/.test(r.title));});
test('Buyer CO never receives generic bidder readiness questions',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Bid must be received by deadline.',category:'Submission',status:'Unknown'}]; sample.clarificationQuestions=[{question:'Confirm readiness for Submission Deadline.',whyItMatters:'Bid team readiness.',relatedRequirement:'Submission Deadline',priority:'High',audience:'Buyer / Contracting Officer'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'buyer-readiness'}); assert(!out.clarificationQuestions.some(q=>q.audience==='Buyer / Contracting Officer'&&/confirm readiness/i.test(q.question)));});
