test('submission method readiness routes to Internal Bid Team',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Electronic submission required; hard copies will not be accepted.',category:'Submission',status:'Unknown'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'method-route'}); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='SUBMISSION_METHOD')?.audience,'Internal Bid Team');});
test('supplier registration readiness routes to Internal Bid Team',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Supplier must enroll in LSU Workday.',category:'Registration',status:'Unknown'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'reg-route'}); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='SUPPLIER_REGISTRATION')?.audience,'Internal Bid Team');});
test('technical capability routes to Supplier Manufacturer',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'PIV technical specification must be met by manufacturer model.',category:'Technical',status:'Unknown'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'tech-route'}); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='MANUFACTURER_MODEL_REQUIRED')?.audience,'Supplier / Manufacturer');});
test('missing buyer-controlled insurance attachment routes to Buyer CO',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Referenced insurance attachment is missing and insurance limits are unclear.',category:'Insurance',status:'Needs Clarification',evidence:'Referenced insurance attachment is missing.'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'insurance-buyer'}); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='INSURANCE_REQUIREMENTS')?.audience,'Buyer / Contracting Officer');});
test('clarification deduplication prevents generic and specific duplicates',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Supplier must enroll in LSU Workday.',category:'Registration',status:'Unknown'}]; sample.clarificationQuestions=[{question:'Confirm LSU Workday enrollment and W-9/W-8 readiness.',whyItMatters:'Internal readiness.',relatedRequirement:'Supplier Registration',priority:'High',audience:'Internal Bid Team'},{question:'Confirm readiness for Supplier Registration.',whyItMatters:'Generic readiness.',relatedRequirement:'Supplier Registration',priority:'High',audience:'Internal Bid Team'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'clar-dedupe'}); assert.equal(out.clarificationQuestions.filter(q=>q.relatedRequirement==='SUPPLIER_REGISTRATION'&&q.audience==='Internal Bid Team').length,1);});
test('equivalent extraction wording keeps same canonical IDs and score',()=>{const a=JSON.parse(JSON.stringify(base)); const b=JSON.parse(JSON.stringify(base)); a.complianceMatrix=[{...a.complianceMatrix[0],requirement:'Late receipt at lsubids@lsu.edu; late bids will not be accepted.',category:'Other',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Quote net pricing FOB LSU Destination inclusive of shipping.',category:'Commercial',status:'Unknown'}]; b.complianceMatrix=[{...b.complianceMatrix[0],requirement:'Bid must be received by the deadline.',category:'Submission',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'FOB Destination pricing is required.',category:'Other',status:'Needs Clarification'}]; const outA=validateAnalysis(a,{modelUsed:'m',requestId:'eq-a'}); const outB=validateAnalysis(b,{modelUsed:'m',requestId:'eq-b'}); assert.deepEqual(outA.canonicalRequirements?.map(r=>r.canonicalKey),outB.canonicalRequirements?.map(r=>r.canonicalKey)); assert.equal(outA.opportunityScore.score,outB.opportunityScore.score);});

test('9030000-style extraction variants produce identical canonical IDs counts scores and recommendation',()=>{const a=JSON.parse(JSON.stringify(base)); const b=JSON.parse(JSON.stringify(base)); a.complianceMatrix=[{...a.complianceMatrix[0],requirement:'Bid must be received by 11:00 AM CT; late bids will not be accepted.',category:'Other',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Hard-copy bids will not be evaluated; electronic submission required.',category:'Other',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Submit original and redacted copy if applicable.',category:'Submission',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Authorized signature required.',category:'Administrative',status:'Unknown'}]; b.complianceMatrix=[{...b.complianceMatrix[0],requirement:'Late receipt at lsubids@lsu.edu is not accepted.',category:'Submission',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'Hard copies will not be accepted. Submit electronically.',category:'Submission',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'Original/redacted electronic submission copy requirement.',category:'Other',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'Signed by authorized representative.',category:'Other',status:'Needs Clarification'}]; const outA=validateAnalysis(a,{modelUsed:'m',requestId:'903a'}); const outB=validateAnalysis(b,{modelUsed:'m',requestId:'903b'}); assert.deepEqual(outA.canonicalRequirements?.map(r=>r.canonicalKey),outB.canonicalRequirements?.map(r=>r.canonicalKey)); assert.equal(outA.canonicalRequirements?.length,outB.canonicalRequirements?.length); assert.deepEqual(outA.subScores,outB.subScores); assert.equal(outA.opportunityScore.score,outB.opportunityScore.score); assert.equal(outA.recommendation,outB.recommendation);});
test('hard-copy rejection maps to submission method without OTHER fallback',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Hard-copy bids will not be evaluated.',category:'Other',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'hard-copy'}); assert(out.canonicalRequirements?.some(r=>r.canonicalKey==='SUBMISSION_METHOD')); assert(!out.canonicalRequirements?.some(r=>r.canonicalKey.startsWith('OTHER_HARD_COPY')));});
