test('same canonical 64-style inputs produce same deterministic score and recommendation',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Bid must be received by 11:00 AM CT.',category:'Submission',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Electronic submission required.',category:'Submission',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Authorized signature required.',category:'Administrative',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Quote net pricing FOB LSU Destination inclusive of shipping.',category:'Commercial',status:'Unknown'}]; const scores=new Set<string>(); for(let i=0;i<4;i++){const out=validateAnalysis(JSON.parse(JSON.stringify(sample)),{modelUsed:'m',requestId:`stable64-${i}`}); scores.add(`${out.opportunityScore.score}:${out.recommendation}:${out.canonicalRequirements?.map(r=>r.canonicalKey).join(',')}`);} assert.equal(scores.size,1);});

test('LSU PIV technical threshold variants collapse to stable catalog parent',()=>{const a=JSON.parse(JSON.stringify(base)); const b=JSON.parse(JSON.stringify(base)); a.complianceMatrix=[{...a.complianceMatrix[0],requirement:'Sampling rate shall be at least 625 Hz.',category:'Technical',status:'Unknown'},{...a.complianceMatrix[0],requirement:'15-minute acquisition with 1.0 m x 1.0 m field of view, maximum 2 mm vector spacing, SNR 100, and less-than-10-second data latency.',category:'Technical',status:'Unknown'}]; b.complianceMatrix=[{...b.complianceMatrix[0],requirement:'System must operate at minimum 625 frames per second.',category:'Technical',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'PIV technical performance includes field of view, vector spacing, signal-to-noise ratio, and latency thresholds.',category:'Technical',status:'Needs Clarification'}]; const outA=validateAnalysis(a,{modelUsed:'m',requestId:'piv-a'}); const outB=validateAnalysis(b,{modelUsed:'m',requestId:'piv-b'}); assert.deepEqual(outA.canonicalRequirements?.filter(r=>r.category==='Technical').map(r=>r.canonicalKey),outB.canonicalRequirements?.filter(r=>r.category==='Technical').map(r=>r.canonicalKey)); assert.equal(outA.canonicalRequirements?.filter(r=>r.canonicalKey==='TECHNICAL_COMPLIANCE').length,1); assert.equal(outB.canonicalRequirements?.filter(r=>r.canonicalKey==='TECHNICAL_COMPLIANCE').length,1);});
test('installation training warranty and laser safety map to dedicated catalog IDs',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Onsite installation is required.',category:'Technical',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Onsite training shall be provided.',category:'Technical',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'One-year warranty required.',category:'Commercial',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Comply with ANSI Z136.1 and IEC 60825-1 laser safety standards.',category:'Legal',status:'Unknown'}]; const ids=validateAnalysis(sample,{modelUsed:'m',requestId:'dedicated'}).canonicalRequirements?.map(r=>r.canonicalKey)||[]; for(const id of ['INSTALLATION_REQUIRED','TRAINING_REQUIRED','WARRANTY_REQUIRED','LASER_SAFETY_COMPLIANCE']) assert(ids.includes(id));});
test('catalog-backed fixture variants have identical owners audiences score and recommendation',()=>{const a=JSON.parse(JSON.stringify(base)); const b=JSON.parse(JSON.stringify(base)); a.complianceMatrix=[{...a.complianceMatrix[0],requirement:'Supplier must identify manufacturer and model.',category:'Technical',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Sampling rate shall be at least 625 Hz.',category:'Technical',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Hard copies will not be accepted.',category:'Submission',status:'Unknown'},{...a.complianceMatrix[0],requirement:'Workday enrollment required.',category:'Registration',status:'Unknown'},{...a.complianceMatrix[0],requirement:'W-9 required.',category:'Registration',status:'Unknown'}]; b.complianceMatrix=[{...b.complianceMatrix[0],requirement:'Bidder shall state brand/model number.',category:'Other',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'System must operate at minimum 625 frames per second.',category:'Technical',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'Only electronic email bids will be evaluated.',category:'Other',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'Supplier registration in Workday is required.',category:'Other',status:'Needs Clarification'},{...b.complianceMatrix[0],requirement:'W-8 tax documentation required.',category:'Administrative',status:'Needs Clarification'}]; const outA=validateAnalysis(a,{modelUsed:'m',requestId:'cat-a'}); const outB=validateAnalysis(b,{modelUsed:'m',requestId:'cat-b'}); assert.deepEqual(outA.canonicalRequirements?.map(r=>r.canonicalKey),outB.canonicalRequirements?.map(r=>r.canonicalKey)); assert.deepEqual(outA.canonicalRequirements?.map(r=>r.actionOwner),outB.canonicalRequirements?.map(r=>r.actionOwner)); assert.deepEqual(outA.clarificationQuestions.map(q=>`${q.relatedRequirement}:${q.audience}`),outB.clarificationQuestions.map(q=>`${q.relatedRequirement}:${q.audience}`)); assert.deepEqual(outA.subScores,outB.subScores); assert.equal(outA.opportunityScore.score,outB.opportunityScore.score); assert.equal(outA.recommendation,outB.recommendation);});
test('catalog fallback remains clean and empty bidder profile creates no active hard stop',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Unique solicitation-specific packaging label must be blue.',category:'Other',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'fallback-clean'}); assert(!out.canonicalRequirements?.some(r=>/OTHER_OTHER|COMMERCIAL_COMMERCIAL|SUBMISSION_SUBMISSION/.test(r.canonicalKey))); assert.deepEqual(out.hardStops,[]);});

test('hard-copy and electronic submission variants never emit OTHER fallback',()=>{for(const requirement of ['Hard copy submission to the buyer is not accepted; use Return Bid To email.','Do not submit directly to the buyer; submit electronically only.','Email submission required through the Return Bid To email.']){const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement,category:'Other',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:requirement}); assert(out.canonicalRequirements?.some(r=>r.canonicalKey==='SUBMISSION_METHOD')); assert(!out.canonicalRequirements?.some(r=>/^OTHER_.*HARD|OTHER_HARD/.test(r.canonicalKey)));}});
test('authorized signature routes Buyer CO only for actual signature format ambiguity',()=>{const internal=JSON.parse(JSON.stringify(base)); internal.complianceMatrix=[{...internal.complianceMatrix[0],requirement:'Authorized original signature is required.',category:'Administrative',status:'Unknown',evidence:'Authorized original signature is required.'}]; internal.clarificationQuestions=[]; const outInternal=validateAnalysis(internal,{modelUsed:'m',requestId:'sig-internal'}); assert.equal(outInternal.clarificationQuestions.find(q=>q.relatedRequirement==='AUTHORIZED_SIGNATURE')?.audience,'Internal Bid Team'); const buyer=JSON.parse(JSON.stringify(base)); buyer.complianceMatrix=[{...buyer.complianceMatrix[0],requirement:'Original signature requirement appears to conflict with electronic submission; signature format is unclear.',category:'Administrative',status:'Needs Clarification',evidence:'Original signature conflicts with electronic submission; signature format is unclear.'}]; buyer.clarificationQuestions=[]; const outBuyer=validateAnalysis(buyer,{modelUsed:'m',requestId:'sig-buyer'}); assert.equal(outBuyer.clarificationQuestions.find(q=>q.relatedRequirement==='AUTHORIZED_SIGNATURE')?.audience,'Buyer / Contracting Officer');});
test('award basis conflict routes Buyer Contracting Officer',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Special terms state all-or-none award while standard terms allow separate grouped or all-or-none award.',category:'Commercial',status:'Needs Clarification',evidence:'All-or-none award conflicts with separate/grouped/all-or-none award terms.'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'award-conflict'}); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='AWARD_BASIS')?.audience,'Buyer / Contracting Officer');});
test('insurance buyer attachment and bidder capability keep separate audience and owner',()=>{const missing=JSON.parse(JSON.stringify(base)); missing.complianceMatrix=[{...missing.complianceMatrix[0],requirement:'Referenced insurance attachment is missing and official insurance limits are unclear.',category:'Insurance',status:'Needs Clarification',evidence:'Referenced insurance attachment is missing.'}]; missing.clarificationQuestions=[]; const outMissing=validateAnalysis(missing,{modelUsed:'m',requestId:'ins-missing'}); assert.equal(outMissing.clarificationQuestions.find(q=>q.relatedRequirement==='INSURANCE_REQUIREMENTS')?.audience,'Buyer / Contracting Officer'); assert.equal(outMissing.complianceMatrix.find(c=>c.id==='INSURANCE_REQUIREMENTS')?.owner,'Internal Bid Team'); const capability=JSON.parse(JSON.stringify(base)); capability.complianceMatrix=[{...capability.complianceMatrix[0],requirement:'Insurance capability is unknown for the bidder.',category:'Insurance',status:'Unknown',evidence:'Bidder insurance capability unknown.'}]; capability.clarificationQuestions=[]; const outCapability=validateAnalysis(capability,{modelUsed:'m',requestId:'ins-capability'}); assert.equal(outCapability.clarificationQuestions.find(q=>q.relatedRequirement==='INSURANCE_REQUIREMENTS')?.audience,'Internal Bid Team');});
test('duplicate technical evidence produces one TECHNICAL_COMPLIANCE gate',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Sampling rate at least 625 Hz.',category:'Technical',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'System must operate at minimum 625 frames per second.',category:'Technical',status:'Needs Clarification'},{...sample.complianceMatrix[0],requirement:'Field of view and SNR technical thresholds apply.',category:'Technical',status:'Unknown'}]; sample.clarificationGates=['Confirm the proposed technical solution meets all mandatory technical thresholds.']; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'tech-gate-once'}); assert.equal(out.clarificationGates.filter(g=>g==='Confirm the proposed technical solution meets all mandatory technical thresholds.').length,1);});


test('debarment suspension wording maps to one DEBARMENT_CERTIFICATION requirement',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Supplier certifies it is not suspended or debarred.',category:'Legal',status:'Unknown'},{...sample.complianceMatrix[0],requirement:'Subcontractors and principals are not suspended, debarred, or excluded.',category:'Other',status:'Needs Clarification'},{...sample.complianceMatrix[0],requirement:'Certification of no suspension or debarment is required.',category:'Certification',status:'Unknown'}]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'debar'}); const matches=out.canonicalRequirements?.filter(r=>r.canonicalKey==='DEBARMENT_CERTIFICATION')||[]; assert.equal(matches.length,1); assert.equal(matches[0]?.title,'Suspension and Debarment Certification'); assert(!out.canonicalRequirements?.some(r=>/^LEGAL_CERTIFY_SUBCONTRACTORS|^OTHER_CERTIFY_THAT/.test(r.canonicalKey)));});

test('authoritative buyer questions are generated separately from internal owners',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Special terms state all-or-none award while standard terms allow separate grouped or all-or-none award.',category:'Commercial',status:'Needs Clarification',evidence:'Special terms all-or-none conflict with standard separate/grouped/all-or-none award provision.',owner:'Internal Bid Team'},{...sample.complianceMatrix[0],requirement:'Bid deadline uses 11:00 AM CT while inquiry deadline uses 4:30 PM CST and questions are due a relative number of business days before bid opening.',category:'Submission',status:'Needs Clarification',evidence:'CT/CST and relative business days inquiry deadline interpretation is unclear.',owner:'Internal Bid Team'},{...sample.complianceMatrix[0],requirement:'Referenced insurance attachment is missing and official insurance limits are not provided.',category:'Insurance',status:'Needs Clarification',evidence:'Referenced insurance attachment is missing and limits are not provided.',owner:'Internal Bid Team'}]; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'buyer-auth'}); for(const key of ['AWARD_BASIS','SUBMISSION_DEADLINE','INSURANCE_REQUIREMENTS']) assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement===key)?.audience,'Buyer / Contracting Officer'); assert.equal(out.complianceMatrix.find(c=>c.id==='AWARD_BASIS')?.owner,'Internal Bid Team'); assert.equal(out.complianceMatrix.find(c=>c.id==='INSURANCE_REQUIREMENTS')?.owner,'Internal Bid Team'); assert(out.clarificationQuestions.some(q=>/all-or-none basis/.test(q.question))); assert(out.clarificationQuestions.some(q=>/coverage limits/.test(q.question))); assert(out.clarificationQuestions.some(q=>/CT\/CST|relative inquiry-deadline/.test(q.question)));});

test('local deterministic pipeline handles hard-copy mapping owner audience and duplicate gates without throwing',()=>{const sample=JSON.parse(JSON.stringify(base)); sample.complianceMatrix=[{...sample.complianceMatrix[0],requirement:'Hard copy submission to the buyer is not accepted; use Return Bid To email.',category:'Other',mandatory:true,status:'Unknown',riskLevel:'High',evidence:'Hard copy submission to the buyer is not accepted; use Return Bid To email.',actionNeeded:'Confirm submission method',owner:'Buyer / Contracting Officer'},{...sample.complianceMatrix[0],requirement:'Referenced insurance attachment is missing and official insurance limits are unclear.',category:'Insurance',mandatory:true,status:'Needs Clarification',riskLevel:'High',evidence:'Referenced insurance attachment is missing.',actionNeeded:'Get insurance attachment',owner:'Buyer / Contracting Officer'},{...sample.complianceMatrix[0],requirement:'Sampling rate at least 625 Hz.',category:'Technical',mandatory:true,status:'Unknown',riskLevel:'High',evidence:'Sampling rate at least 625 Hz.',actionNeeded:'Confirm technical compliance',owner:'Supplier / Manufacturer'},{...sample.complianceMatrix[0],requirement:'System must operate at minimum 625 frames per second.',category:'Technical',mandatory:true,status:'Needs Clarification',riskLevel:'High',evidence:'System must operate at minimum 625 frames per second.',actionNeeded:'Confirm technical compliance',owner:'Supplier / Manufacturer'}]; sample.clarificationGates=['Confirm the proposed technical solution meets all mandatory technical thresholds.','Confirm the proposed technical solution meets all mandatory technical thresholds.']; sample.clarificationQuestions=[]; const out=validateAnalysis(sample,{modelUsed:'m',requestId:'local-regression'}); assert(out.canonicalRequirements?.some(r=>r.canonicalKey==='SUBMISSION_METHOD')); assert(!out.canonicalRequirements?.some(r=>/^OTHER_.*HARD/.test(r.canonicalKey))); assert.equal(out.complianceMatrix.find(c=>c.id==='INSURANCE_REQUIREMENTS')?.owner,'Internal Bid Team'); assert.equal(out.clarificationQuestions.find(q=>q.relatedRequirement==='INSURANCE_REQUIREMENTS')?.audience,'Buyer / Contracting Officer'); assert.equal(out.clarificationGates.filter(g=>g==='Confirm the proposed technical solution meets all mandatory technical thresholds.').length,1); assert.deepEqual(out.hardStops,[]);});
